from pathlib import Path
ROOT=Path(".")
ROOT.joinpath("src/views/home.rs").write_text("//! home\nuse crate::models::pagination::PageNavItem;\nuse crate::models::video::VideoThumb;\nuse crate::views::RenderContext;\npub const HOME_SEO_INTRO: &str = \"intro\";\npub const HOME_SEO_FOOTER: &str = \"footer\";\npub const THUMB_LAZY_PLACEHOLDER: &str = \"data:image/gif;base64,R0lGODlhAQABAJAAAAAAAAAAACH5BAEUAAAALAAAAAABAAEAAAICRAEAOw==\";\n#[derive(Debug, Clone, PartialEq, Eq)]\npub struct HomeFilterView { pub all_href: String, pub hd_href: String, pub newest_href: String, pub most_viewed_href: String, pub most_commented_href: String, pub all_active: bool, pub hd_active: bool, pub newest_selected: bool, pub most_viewed_selected: bool, pub most_commented_selected: bool, }\n#[derive(Debug, Clone, PartialEq, Eq)]\npub enum HomePaginationItem { Current(u32), Link { href: String, label: String }, Ellipsis, Previous { href: String }, Next { href: String }, }\nimpl HomePaginationItem { pub fn from_page_nav(items: Vec<PageNavItem>) -> Vec<Self> { items.into_iter().map(|item| match item { PageNavItem::Current(p) => Self::Current(p), PageNavItem::Link { href, page } => Self::Link { href, label: page.to_string() }, PageNavItem::Ellipsis => Self::Ellipsis, PageNavItem::Previous { href, .. } => Self::Previous { href }, PageNavItem::Next { href, .. } => Self::Next { href }, }).collect() } }\n#[derive(Debug, Clone)]\npub struct HomePageView { pub ctx: RenderContext, pub videos: Vec<VideoThumb>, pub pagination: Vec<HomePaginationItem>, pub filters: HomeFilterView, }\nimpl HomePageView { pub fn has_videos(&self) -> bool { !self.videos.is_empty() } }\n")
print("ok")
